// Sentry webhook 验签(注意:对 RAW body,不要先 JSON 反序列化再 stringify)
import crypto from "crypto";
function verifySentry(rawBody, sigHeader, clientSecret) {
  const digest = crypto.createHmac("sha256", clientSecret)
                       .update(rawBody, "utf8").digest("hex");
  return crypto.timingSafeEqual(Buffer.from(digest), Buffer.from(sigHeader));
}
// 1s 约束:验签通过后立刻 200,再异步止血
app.post("/sentry", express.raw({type:"*/*"}), (req,res)=>{
  if(req.get("sentry-hook-resource")!=="event_alert") return res.sendStatus(204);
  if(!verifySentry(req.body, req.get("sentry-hook-signature"), SECRET)) return res.sendStatus(401);
  res.sendStatus(200);              // 先回,满足 1s
  queueRollback(JSON.parse(req.body)); // 后台切流量回 last-good revision
});
